.darma-loader-darma-custom-151 {
  color: #4f46e5;
width: 45px;
aspect-ratio: 1;
--c: linear-gradient(135deg,currentColor,var(--loader-secondary-color));
--r1: radial-gradient(farthest-side at bottom,currentColor 93%,#0000);
--r2: radial-gradient(farthest-side at top ,currentColor 93%,#0000);
background:
var(--c) ,var(--r1),var(--r2),
var(--c) ,var(--r1),var(--r2),
var(--c) ,var(--r1),var(--r2);
background-repeat: no-repeat;
animation: darma-loader-darma-custom-151-l1 1s infinite alternate;
}
@keyframes darma-loader-darma-custom-151-l1 {
0%,10% {
background-size: 8px 0,8px 4px,8px 4px;
background-position: 0 50%,0 calc(50% - 2px),0 calc(50% + 2px),50% 50%,50% calc(50% - 2px),50% calc(50% + 2px),100% 50%,100% calc(50% - 2px),100% calc(50% + 2px);
}
90%,100% {
background-size: 8px 100%,8px 4px, 8px 4px;
background-position: 0 50%,0 -2px,0 calc(100% + 2px),50% 50%,50% -2px,50% calc(100% + 2px),100% 50%,100% -2px,100% calc(100% + 2px);
}
}

